import{_ as o,o as i,c as a,a2 as c}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Architettura","description":"","frontmatter":{},"headers":[],"relativePath":"it/guide/architecture.md","filePath":"it/guide/architecture.md"}'),t={name:"it/guide/architecture.md"};function d(r,e,l,n,s,u){return i(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="architettura" tabindex="-1">Architettura <a class="header-anchor" href="#architettura" aria-label="Permalink to &quot;Architettura&quot;">​</a></h1><h2 id="come-funziona-la-risoluzione" tabindex="-1">Come funziona la risoluzione <a class="header-anchor" href="#come-funziona-la-risoluzione" aria-label="Permalink to &quot;Come funziona la risoluzione&quot;">​</a></h2><p><code>resolveFor()</code> è il cuore dell&#39;autorizzazione contestuale di Clearance - vedi <a href="/clearance-docs/it/features/contextual-authorization.html">Contextual Authorization</a> per l&#39;API completa. Unisce tre fonti, in questo ordine di precedenza:</p><ol><li><strong>Concessioni di ruolo contestuali</strong> - permessi dai ruoli che l&#39;utente detiene specificamente in questo contesto (<code>clr_role_ctx</code>).</li><li><strong>Concessioni di ruolo globali</strong> - permessi dai ruoli Spatie assegnati globalmente all&#39;utente (così <code>super_admin</code> e altri ruoli globali soddisfano <code>canIn()</code> per qualsiasi contesto).</li><li><strong>Override per contesto</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> aggiunge un permesso oltre a quanto sopra; <code>forced_off</code> lo rimuove, anche se il permesso era stato concesso da un ruolo globale. Un diniego vince sempre.</li></ol><div class="warning custom-block"><p class="custom-block-title">Un diniego vince sempre</p><p><code>forced_off</code> prevale su qualsiasi permesso concesso da un ruolo globale o da una concessione di ruolo contestuale. Non esiste modo di &quot;superare in priorità&quot; un override <code>forced_off</code> per lo stesso utente/permesso/contesto se non rimuovendolo.</p></div><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><p>Clearance possiede 6 tabelle e non altera mai le tabelle core di Spatie (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>). Tutte le FK che referenziano <code>roles.id</code>/<code>permissions.id</code> fanno cascade on delete salvo diversa indicazione; le tabelle di Spatie non hanno FK che puntano verso <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>Tabella</th><th>Colonne chiave</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (unici insieme) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - metadati di visualizzazione per un ruolo o una guardia</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (unico, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (FK nullabile -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - ruolo ceiling</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (unico), <code>driver</code>, <code>provider</code> - guardie gestite tramite il pannello</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (unico), <code>value</code> - archivio chiave/valore a runtime (ruolo predefinito, ecc.)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - assegnazioni di ruolo contestuali, uniche per <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - override dei permessi per utente e per contesto</td></tr></tbody></table><h2 id="non-tocca-mai-le-tabelle-di-spatie" tabindex="-1">Non tocca mai le tabelle di Spatie <a class="header-anchor" href="#non-tocca-mai-le-tabelle-di-spatie" aria-label="Permalink to &quot;Non tocca mai le tabelle di Spatie&quot;">​</a></h2><p>Clearance è progettato per convivere accanto a <code>spatie/laravel-permission</code>, non per sostituirlo. Ogni record <code>Role</code> e <code>Permission</code> che un pannello Clearance crea o modifica è un genuino modello Spatie, memorizzato nelle tabelle proprie di Spatie. Clearance non esegue mai una migrazione che aggiunga una colonna a, o scriva una FK da, una qualsiasi tra <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, o <code>role_has_permissions</code>.</p><p>Tutti i dati propri di Clearance - metadati di visualizzazione, ambito e ceiling dei ruoli, assegnazioni contestuali, override per contesto, definizioni delle guardie e impostazioni - vivono esclusivamente nelle 6 tabelle <code>clr_*</code> sopra elencate. Questo significa:</p><ul><li>Disinstallare Clearance non rischia mai di corrompere i dati esistenti di ruoli/permessi Spatie.</li><li>Qualsiasi codice che già legge direttamente i modelli o le tabelle di Spatie continua a funzionare senza modifiche.</li><li>Le funzionalità contestuali e di ceiling di Clearance sono livelli puramente additivi risolti a runtime (tramite <code>resolveFor()</code> e <code>RoleService</code>), non incorporati nello schema di Spatie.</li></ul><h2 id="correlati" tabindex="-1">Correlati <a class="header-anchor" href="#correlati" aria-label="Permalink to &quot;Correlati&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/features/contextual-authorization.html">Contextual Authorization</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, direttive Blade, <code>ContextService</code></li><li><a href="/clearance-docs/it/features/roles.html">Roles</a> - ambito e ruoli ceiling, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/it/guide/migration.html">Migration</a> - backfill di <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> su un&#39;installazione Spatie esistente</li><li><a href="/clearance-docs/it/guide/security.html">Security</a> - come il modello di ceiling e override previene l&#39;escalation di privilegi</li></ul>',14)])])}const _=o(t,[["render",d]]);export{m as __pageData,_ as default};
